CREATE TABLE users (
  id SERIAL PRIMARY KEY,  -- auto-increments: 1, 2, 3, 4...
  name TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL
);

-- Now each user has a guaranteed unique ID
INSERT INTO users (name, email) VALUES ('Alice', 'alice@mail.com');
-- id is automatically set to 1
INSERT INTO users (name, email) VALUES ('Alice', 'alice2@mail.com');
-- id is automatically set to 2 (different Alice, no confusion!)
